import{c as e}from"./app.d8523fce.js";import{_ as t}from"./plugin-vue_export-helper.21dcd24c.js";var a="/angular-security-training/assets/jwt-structure.af7c9b60.png";const i={},n=e('<h1 id="_1-1-jwt-overview" tabindex="-1"><a class="header-anchor" href="#_1-1-jwt-overview" aria-hidden="true">#</a> 1.1 JWT Overview</h1><h2 id="jwt-in-a-nutshell" tabindex="-1"><a class="header-anchor" href="#jwt-in-a-nutshell" aria-hidden="true">#</a> JWT in a nutshell</h2><p>JSON Web Token (JWT) is an open standard (RFC 7519) that defines a compact and self-contained way for securely transmitting information between parties as a JSON object.</p><ul><li><p>Information can be <strong>verified</strong> and trusted because it is <strong>digitally signed</strong>.</p></li><li><p>Used in <strong>URL</strong>, <strong>POST</strong> parameter, or an <strong>HTTP header</strong>.</p></li><li><p>Used to <strong>authenticate an API</strong>.</p></li></ul><h2 id="what-is-jwt-structure" tabindex="-1"><a class="header-anchor" href="#what-is-jwt-structure" aria-hidden="true">#</a> What is JWT Structure ?</h2><p>JWT looks like the following in its JWS compact serialization :</p><p><img src="'+a+'" alt="jwt-structure"></p><p><strong>JOSE Header:</strong> Indicates to the receiver which type of signature algorithm to use for payload validation.</p><p><strong>JWS Payload:</strong> Can contain any information but note that <strong>the content is not encrypted</strong>. So any information that you put in the token is readable by anyone who intercepts it. It also indicates the bearer standard properties for JWT Based Authentication:</p><ul><li><code>iss</code> means the issuing entity, in this case, our authentication server</li><li><code>iat</code> is the timestamp of creation of the JWT</li><li><code>sub</code> contains the technical identifier of the user</li><li><code>exp</code> contains the token expiration timestamp</li></ul><p><strong>JWS Signature:</strong> is a MAC (Message authentication code) produced with the header, payload and the secret key.</p><h2 id="what-is-a-bearer-token" tabindex="-1"><a class="header-anchor" href="#what-is-a-bearer-token" aria-hidden="true">#</a> What is a Bearer Token ?</h2><p>The Bearer Token is a <strong>JWT used during an authentication process for authorization purpose</strong>. Bearer Tokens are part of the OAuth V2 standard and widely adopted by many APIs. In the JWT authorization workflow, the bearer token becomes a signed temporary replacement for the login/password credentials.</p><h2 id="what-are-jwt-benefits-for-authentication" tabindex="-1"><a class="header-anchor" href="#what-are-jwt-benefits-for-authentication" aria-hidden="true">#</a> What are JWT benefits for authentication ?</h2><p>The main authentication methods are the following:</p><ul><li>HTTP basic authentication: relies on a simple credential scheme with username:password. They are sent in every request with risk of exposure even if sent in a secure connection. The password management is not trivial as you have to ask the user to change their passwords regularly. This method must be avoided in modern web applications, unless you add a multi-factor authentication layer.</li><li>Authentication Cookies : CSRF and XSS can be mitigated if you always use HttpOnly flag and use signed cookies for authentication. This method is incompatible with REST as it introduces a state into a stateless protocol.</li><li>Signature: Requires private key management. Useful for API authentication only and not adapted for browser/client authentication.</li><li>JWT: Token based authentication widely spread today for both browser / client (SPA) and RESTful API authentication. Secure implementation is needed to avoid potential threats.</li></ul><p>JWT key benefit is to allow the possibility to <strong>separate the Authentication logic from the Application Server</strong>.</p><p>The Application servers become safer and faster by <strong>delegating authentication to a third party server</strong> that can be one of the following:</p><ul><li><p>A centralized in-house custom developed authentication server.</p></li><li><p>A commercial product like LDAP capable of issuing JWTs.</p></li><li><p>A completely external third-party authentication provider such as for example Auth0.</p></li></ul><p>Another benefit is to make the application server completely stateless and no need to store password digests in application server database.</p>',20);function o(r,s){return n}var d=t(i,[["render",o]]);export{d as default};
